// Telegram message: single-line text + inline buttons with callback_data
// Button text: "/synestry user_id invited_user_id"
// callback_data: "synestry|user_id|invited_user_id"

const items = $input.all();

const kb = [];
for (const { json } of items) {
  const rec = json.fields ?? json;

  const userId = String(rec['user id'] ?? rec.user_id ?? '').trim();
  const acceptedUserId = String(rec['accepted user id'] ?? rec.invited_user_id ?? '').trim();
  const acceptedUserName = String(rec['accepted user name'] ?? rec.invited_user_name ?? '').trim();
  if (!userId || !acceptedUserId) continue;

  const btnText = `/synestry ${acceptedUserName}`;
  const data = `synestry:${invitedUserId}`;

  // одна кнопка в строке
  kb.push([{ text: btnText, callback_data: data }]);
}

// одна строка текста
const text =
  kb.length > 0
    ? 'Доступные Synestry:'
    : 'Нет подтверждённых пар.';

return [
  {
    json: {
      text,
      parse_mode: 'Markdown',
      reply_markup: { inline_keyboard: kb },
      total: kb.length,
    },
  },
];

// Code node
const items = $input.all();
const kb = [];

for (const { json } of items) {
  const rec = json.fields ?? json;
  const acceptedUserId = String(rec['accepted user id'] ?? rec.invited_user_id ?? '').trim();
  const acceptedUserName = String(rec['accepted user name'] ?? rec.invited_user_name ?? '').trim();

  const btnText = `/synestry ${acceptedUserName}`;
  const data = `synestry:${acceptedUserId}`;
  kb.push([{ text: btnText, callback_data: data }]);
}

const text = kb.length > 0 ? 'Доступные Synestry:' : 'Нет подтверждённых пар.';

// забираем chat_id из узла Set без привязки к pair
const chatId = $item(0).$node['Set'].json.chat_id;

return [{
  json: {
    chat_id: chatId,
    text,
    parse_mode: 'Markdown',
    reply_markup: { inline_keyboard: kb },
    total: kb.length,
  },
}];
